scripts.script:
function tradesData() {
  var quarters = ['Q1', 'Q2', 'Q3', 'Q4']
  var days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri']
  var out = []
  for (var i = 0; i < 90; i++) {
    out.push({
      quarter: quarters[Math.floor(i / 23) % 4],
      day: days[i % 5],
      outcome: i % 3 === 0 ? 'Loss' : 'Gain',
    })
  }
  return out
}

// Register the shared records BEFORE the charts are constructed.
ApexCharts.crossfilter({ id: 'trades', records: tradesData() })

vanilla-js-script:
// charts[0] = heatmap (target), charts[1] = outcome donut, charts[2] = day bar.
var cf = ApexCharts.getCrossfilter('trades')
var readout = document.getElementById('cf-readout')

if (cf) {
  cf.on('change', function (state) {
    var ids = Object.keys(state.filters)
    readout.textContent =
      state.filteredCount + ' / ' + state.total + ' trades   (active: ' +
      (ids.length ? ids.join(', ') : 'none') + ')'
  })
  var s = cf.state()
  readout.textContent = s.filteredCount + ' / ' + s.total + ' trades   (active: none)'
}

document.getElementById('cf-reset').addEventListener('click', function () {
  if (cf) cf.reset()
})
